class Solution {
    public int minStartingIndex(String s, String pattern) {
        int n = s.length(), m = pattern.length();
        int res = -1, minDiff = n;
        for (int i = 0; i <= n - m; i++) {
            int diff = 0;
            for (int j = 0; j < m; j++) {
                if (s.charAt(i + j) != pattern.charAt(j)) diff++;
            }
            if (diff <= 1 && diff < minDiff) {
                res = i;
                minDiff = diff;
            }
        }
        return res;
    }
}
```
